func getBadResponse() *http.Response {
	header := make(map[string][]string)
	header["Proxy-Authenticate"] = []string{"Basic"}
	header["Connection"] = []string{"close"}
	res := &http.Response{
		Status:		"407 Not authorized",
		StatusCode:	407,
		Proto:		"HTTP/1.1",
		ProtoMajor:	1,
		ProtoMinor:	1,
		Header:		header,
	}
	return res
}
